{
  "name": "Nexus AI: Multi-Model Platform",
  "description": "An all-in-one AI platform that provides a unified interface to interact with multiple leading AI models like Google Gemini. Features a real-time chat interface and an AI-powered App Builder to generate code on the fly."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useMemo } from 'react';
import { ThemeProvider, useTheme } from './hooks/useTheme';
import ChatScreen from './components/ChatScreen';
import AppBuilderScreen from './components/AppBuilderScreen';
import { AppMode } from './types';
import { MessageSquare, Code, Sun, Moon } from 'lucide-react';

const App: React.FC = () => {
  return (
    <ThemeProvider>
      <MainApp />
    </ThemeProvider>
  );
};

const MainApp: React.FC = () => {
  const [mode, setMode] = useState<AppMode>(AppMode.CHAT);
  const { theme, toggleTheme } = useTheme();

  const renderedScreen = useMemo(() => {
    switch (mode) {
      case AppMode.CHAT:
        return <ChatScreen />;
      case AppMode.APP_BUILDER:
        return <AppBuilderScreen />;
      default:
        return <ChatScreen />;
    }
  }, [mode]);

  return (
    <div className="min-h-screen font-sans text-gray-800 bg-cover bg-center bg-fixed" style={{backgroundImage: "url('https://picsum.photos/1920/1080?grayscale&blur=5')"}}>
      <div className="min-h-screen w-full flex bg-black/10 dark:bg-black/30">
        {/* Sidebar */}
        <nav className="w-16 md:w-64 p-2 md:p-4 flex flex-col justify-between bg-white/20 dark:bg-black/20 backdrop-blur-xl border-r border-white/30 dark:border-white/10">
          <div>
            <div className="flex items-center justify-center md:justify-start gap-2 mb-10 p-2">
                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-8 h-8 text-indigo-500">
                    <path d="M12 2.25c-5.385 0-9.75 4.365-9.75 9.75s4.365 9.75 9.75 9.75 9.75-4.365 9.75-9.75S17.385 2.25 12 2.25ZM9.606 4.014a8.251 8.251 0 0 1 4.788 0 8.25 8.25 0 0 1 3.515 3.515 8.251 8.251 0 0 1 0 4.788 8.25 8.25 0 0 1-3.515 3.515 8.251 8.251 0 0 1-4.788 0 8.25 8.25 0 0 1-3.515-3.515 8.251 8.251 0 0 1 0-4.788 8.25 8.25 0 0 1 3.515-3.515Z" />
                </svg>
              <h1 className="text-xl font-bold hidden md:block text-gray-900 dark:text-white">Nexus AI</h1>
            </div>
            <ul>
              <SidebarButton
                icon={<MessageSquare size={24} />}
                text="AI Chat"
                active={mode === AppMode.CHAT}
                onClick={() => setMode(AppMode.CHAT)}
              />
              <SidebarButton
                icon={<Code size={24} />}
                text="AI App Builder"
                active={mode === AppMode.APP_BUILDER}
                onClick={() => setMode(AppMode.APP_BUILDER)}
              />
            </ul>
          </div>
          <div>
            <SidebarButton
              icon={theme === 'dark' ? <Sun size={24} /> : <Moon size={24} />}
              text={theme === 'dark' ? 'Light Mode' : 'Dark Mode'}
              onClick={toggleTheme}
            />
          </div>
        </nav>

        {/* Main Content */}
        <main className="flex-1 flex flex-col h-screen">
          {renderedScreen}
        </main>
      </div>
    </div>
  );
};

interface SidebarButtonProps {
  icon: React.ReactNode;
  text: string;
  active?: boolean;
  onClick?: () => void;
}

const SidebarButton: React.FC<SidebarButtonProps> = ({ icon, text, active = false, onClick }) => {
  const baseClasses = 'flex items-center w-full gap-3 px-3 py-3 rounded-lg cursor-pointer transition-all duration-200';
  const activeClasses = 'bg-indigo-500/80 text-white shadow-lg';
  const inactiveClasses = 'text-gray-700 dark:text-gray-300 hover:bg-black/10 dark:hover:bg-white/10';

  return (
    <li className="mb-2">
      <button onClick={onClick} className={`${baseClasses} ${active ? activeClasses : inactiveClasses}`}>
        {icon}
        <span className="hidden md:inline font-medium">{text}</span>
      </button>
    </li>
  );
};

export default App;

export interface ChatMessage {
  id: string;
  role: 'user' | 'model' | 'system';
  content: string;
  image?: string; // base64 encoded image
}

export enum AIProvider {
  GEMINI = 'Google Gemini',
  OPENAI = 'OpenAI (Mock)',
  GROQ = 'Groq (Mock)',
  CLAUDE = 'Claude (Mock)',
}

export interface AIModel {
  id: string;
  name: string;
  provider: AIProvider;
}

export enum AppMode {
  CHAT = 'CHAT',
  APP_BUILDER = 'APP_BUILDER'
}

import { AIModel, AIProvider } from './types';

export const AVAILABLE_MODELS: AIModel[] = [
  { id: 'gemini-3-flash-preview', name: 'Gemini 1.5 Flash', provider: AIProvider.GEMINI },
  { id: 'gemini-3-pro-preview', name: 'Gemini 1.5 Pro', provider: AIProvider.GEMINI },
  { id: 'gpt-4o', name: 'GPT-4o', provider: AIProvider.OPENAI },
  { id: 'gpt-3.5-turbo', name: 'GPT-3.5 Turbo', provider: AIProvider.OPENAI },
  { id: 'llama3-70b-8192', name: 'LLaMA3 70b', provider: AIProvider.GROQ },
  { id: 'mixtral-8x7b-32768', name: 'Mixtral 8x7b', provider: AIProvider.GROQ },
  { id: 'claude-3-opus-20240229', name: 'Claude 3 Opus', provider: AIProvider.CLAUDE },
];

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';

type Theme = 'light' | 'dark';

interface ThemeContextType {
  theme: Theme;
  toggleTheme: () => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export const ThemeProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [theme, setTheme] = useState<Theme>(() => {
    if (typeof window !== 'undefined') {
      const savedTheme = localStorage.getItem('theme');
      if (savedTheme === 'dark' || savedTheme === 'light') {
        return savedTheme;
      }
      return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
    }
    return 'light';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    root.classList.remove(theme === 'dark' ? 'light' : 'dark');
    root.classList.add(theme);
    localStorage.setItem('theme', theme);
  }, [theme]);

  const toggleTheme = () => {
    setTheme((prevTheme) => (prevTheme === 'light' ? 'dark' : 'light'));
  };

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = (): ThemeContextType => {
  const context = useContext(ThemeContext);
  if (!context) {
    throw new Error('useTheme must be used within a ThemeProvider');
  }
  return context;
};

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { AIModel, AIProvider, ChatMessage } from "../types";

// --- Gemini Service ---
// IMPORTANT: This assumes the API_KEY is available as an environment variable.
// In a real browser environment, this should be handled via a secure backend proxy.
// For this self-contained example, we'll proceed assuming `process.env.API_KEY` is accessible.
const API_KEY = process.env.API_KEY;

if (!API_KEY) {
  console.warn("API_KEY environment variable not set. Gemini API calls will fail.");
}

const ai = new GoogleGenAI({ apiKey: API_KEY });

const generateGeminiContent = async (
  modelId: string,
  history: ChatMessage[],
  newMessage: string,
  image: string | null,
  onStream: (chunk: string) => void
) => {
  const model = ai.models[modelId as keyof typeof ai.models] || ai.models['gemini-3-flash-preview'];

  const contents = history.map(msg => ({
    role: msg.role,
    parts: [{ text: msg.content }]
  }));

  const userMessageParts = [{ text: newMessage }];
  if (image) {
    const mimeType = image.startsWith('data:image/jpeg') ? 'image/jpeg' : 'image/png';
    userMessageParts.unshift({
      inlineData: {
        mimeType,
        data: image.split(',')[1],
      },
    });
  }

  contents.push({ role: 'user', parts: userMessageParts });

  const stream = await ai.models.generateContentStream({
    model: modelId,
    contents: contents,
  });

  for await (const chunk of stream) {
    const c = chunk as GenerateContentResponse
    if (c.text) {
        onStream(c.text);
    }
  }
};

const generateGeminiCode = async (prompt: string): Promise<string> => {
    const fullPrompt = `You are an expert web developer. Create a complete, single-file React component using TypeScript and Tailwind CSS based on the following request. The code should be functional and self-contained. Do not include any explanations, just the code inside a single markdown code block. Request: "${prompt}"`;

    const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: fullPrompt
    });

    return response.text || " // Sorry, I couldn't generate the code.";
}

// --- Mock Services ---
const generateMockContent = async (
  modelName: string,
  newMessage: string,
  onStream: (chunk: string) => void
) => {
  const response = `This is a mock response from ${modelName}. You said: "${newMessage}". In a real application, this would be a call to the respective AI's API.`;
  const words = response.split(' ');
  for (let i = 0; i < words.length; i++) {
    await new Promise(resolve => setTimeout(resolve, 50));
    onStream(words[i] + ' ');
  }
};


// --- AI Router ---
export const streamAIResponse = (
  model: AIModel,
  history: ChatMessage[],
  newMessage: string,
  image: string | null,
  onStream: (chunk: string) => void
) => {
  switch (model.provider) {
    case AIProvider.GEMINI:
      return generateGeminiContent(model.id, history, newMessage, image, onStream);
    case AIProvider.OPENAI:
    case AIProvider.GROQ:
    case AIProvider.CLAUDE:
      return generateMockContent(model.name, newMessage, onStream);
    default:
      throw new Error(`Unsupported AI provider: ${model.provider}`);
  }
};

export const generateCode = (prompt: string): Promise<string> => {
    // For now, only Gemini can generate code
    return generateGeminiCode(prompt);
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { ChatMessage, AIModel, AIProvider } from '../types';
import { AVAILABLE_MODELS } from '../constants';
import { streamAIResponse } from '../services/aiService';
import { Paperclip, Send, Bot, User, CornerDownLeft, Copy, Check } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { vscDarkPlus } from 'react-syntax-highlighter/dist/esm/styles/prism';

const ChatScreen: React.FC = () => {
    const [messages, setMessages] = useState<ChatMessage[]>([]);
    const [input, setInput] = useState('');
    const [image, setImage] = useState<string | null>(null);
    const [isLoading, setIsLoading] = useState(false);
    const [selectedModel, setSelectedModel] = useState<AIModel>(AVAILABLE_MODELS[0]);

    const fileInputRef = useRef<HTMLInputElement>(null);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(scrollToBottom, [messages]);

    const handleSendMessage = useCallback(async () => {
        if (input.trim() === '' || isLoading) return;

        const userMessage: ChatMessage = {
            id: Date.now().toString(),
            role: 'user',
            content: input,
            ...(image && { image }),
        };

        setMessages(prev => [...prev, userMessage]);
        setInput('');
        setImage(null);
        setIsLoading(true);

        const modelResponseId = (Date.now() + 1).toString();
        setMessages(prev => [...prev, { id: modelResponseId, role: 'model', content: '' }]);

        try {
            const history = messages.filter(m => m.role !== 'system');

            await streamAIResponse(selectedModel, history, input, image, (chunk) => {
                setMessages(prev =>
                    prev.map(m =>
                        m.id === modelResponseId ? { ...m, content: m.content + chunk } : m
                    )
                );
            });
        } catch (error) {
            console.error("Error streaming AI response:", error);
            setMessages(prev =>
                prev.map(m =>
                    m.id === modelResponseId ? { ...m, content: "Sorry, something went wrong. Please check the console for details." } : m
                )
            );
        } finally {
            setIsLoading(false);
        }
    }, [input, image, isLoading, messages, selectedModel]);

    const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = () => {
                setImage(reader.result as string);
            };
            reader.readAsDataURL(file);
        }
    };

    const handleKeyDown = (event: React.KeyboardEvent<HTMLTextAreaElement>) => {
        if (event.key === 'Enter' && !event.shiftKey) {
            event.preventDefault();
            handleSendMessage();
        }
    };

    return (
        <div className="flex-1 flex flex-col h-full p-4 gap-4 bg-transparent">
             {/* Header */}
            <header className="flex-shrink-0 flex justify-between items-center p-4 rounded-xl bg-white/30 dark:bg-black/30 backdrop-blur-lg border border-white/20 dark:border-white/10 shadow-md">
                <h2 className="text-xl font-bold text-gray-800 dark:text-white">AI Chat</h2>
                <ModelSelector selectedModel={selectedModel} onModelChange={setSelectedModel} />
            </header>

            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-4 space-y-6 rounded-xl bg-white/30 dark:bg-black/30 backdrop-blur-lg border border-white/20 dark:border-white/10 shadow-inner">
                {messages.length === 0 && <WelcomeMessage />}
                {messages.map((msg) => (
                    <Message key={msg.id} message={msg} />
                ))}
                 {isLoading && messages[messages.length-1]?.role === 'model' && messages[messages.length-1]?.content === '' && (
                    <div className="flex items-start gap-4">
                        <div className="p-2 bg-indigo-500 rounded-full text-white"><Bot size={20} /></div>
                        <div className="flex items-center gap-2 pt-2">
                            <span className="w-3 h-3 bg-indigo-400 rounded-full animate-pulse"></span>
                            <span className="w-3 h-3 bg-indigo-400 rounded-full animate-pulse [animation-delay:0.2s]"></span>
                            <span className="w-3 h-3 bg-indigo-400 rounded-full animate-pulse [animation-delay:0.4s]"></span>
                        </div>
                    </div>
                 )}
                <div ref={messagesEndRef} />
            </div>

            {/* Input area */}
            <div className="flex-shrink-0 p-4 rounded-xl bg-white/30 dark:bg-black/30 backdrop-blur-lg border border-white/20 dark:border-white/10 shadow-md">
                <div className="relative">
                    {image && (
                        <div className="absolute bottom-full left-0 mb-2 p-2 bg-black/50 rounded-lg">
                            <img src={image} alt="preview" className="h-20 w-20 object-cover rounded" />
                            <button onClick={() => setImage(null)} className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full h-6 w-6 text-xs">&times;</button>
                        </div>
                    )}
                    <textarea
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        onKeyDown={handleKeyDown}
                        placeholder={`Message ${selectedModel.name}...`}
                        className="w-full bg-white/50 dark:bg-black/50 text-gray-800 dark:text-gray-200 placeholder-gray-500 dark:placeholder-gray-400 p-4 pr-32 rounded-lg border-2 border-transparent focus:border-indigo-500 focus:ring-0 transition-colors resize-none"
                        rows={1}
                        style={{minHeight: "52px"}}
                    />
                    <div className="absolute right-3 top-1/2 -translate-y-1/2 flex items-center gap-2">
                         <button onClick={() => fileInputRef.current?.click()} className="p-2 text-gray-500 hover:text-indigo-500 dark:text-gray-400 dark:hover:text-indigo-400 transition-colors">
                            <Paperclip size={20} />
                        </button>
                        <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
                        <button onClick={handleSendMessage} disabled={isLoading} className="bg-indigo-500 text-white rounded-lg p-2 disabled:bg-indigo-300 hover:bg-indigo-600 transition-all duration-200">
                           {isLoading ? <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div> : <Send size={20} />}
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

const ModelSelector: React.FC<{selectedModel: AIModel, onModelChange: (model: AIModel) => void}> = ({ selectedModel, onModelChange }) => {
    return (
        <select
            value={selectedModel.id}
            onChange={(e) => {
                const model = AVAILABLE_MODELS.find(m => m.id === e.target.value);
                if(model) onModelChange(model);
            }}
            className="bg-white/50 dark:bg-black/50 text-gray-800 dark:text-gray-200 rounded-md py-2 px-3 border border-transparent focus:border-indigo-500 focus:ring-0"
        >
            {Object.values(AIProvider).map(provider => (
                <optgroup label={provider} key={provider}>
                    {AVAILABLE_MODELS.filter(m => m.provider === provider).map(model => (
                        <option key={model.id} value={model.id}>{model.name}</option>
                    ))}
                </optgroup>
            ))}
        </select>
    );
};

const Message: React.FC<{message: ChatMessage}> = ({ message }) => {
    const isUser = message.role === 'user';
    const [hasCopied, setHasCopied] = useState(false);

    const handleCopy = () => {
        navigator.clipboard.writeText(message.content);
        setHasCopied(true);
        setTimeout(() => setHasCopied(false), 2000);
    };

    return (
        <div className={`flex items-start gap-4 ${isUser ? 'justify-end' : ''}`}>
            {!isUser && <div className="flex-shrink-0 p-2 bg-indigo-500 rounded-full text-white"><Bot size={20} /></div>}

            <div className={`max-w-xl w-full p-4 rounded-xl relative group ${isUser ? 'bg-indigo-500 text-white rounded-br-none' : 'bg-white/80 dark:bg-gray-800/80 text-gray-800 dark:text-gray-200 rounded-bl-none'}`}>
                 {message.image && <img src={message.image} alt="attachment" className="rounded-lg mb-2 max-h-64" />}
                <div className="prose prose-sm dark:prose-invert max-w-none prose-p:before:content-none prose-p:after:content-none">
                     <ReactMarkdown
                        remarkPlugins={[remarkGfm]}
                        components={{
                            code({node, inline, className, children, ...props}) {
                                const match = /language-(\w+)/.exec(className || '')
                                return !inline && match ? (
                                    <SyntaxHighlighter
                                        style={vscDarkPlus}
                                        language={match[1]}
                                        PreTag="div"
                                        {...props}
                                    >
                                        {String(children).replace(/\n$/, '')}
                                    </SyntaxHighlighter>
                                ) : (
                                    <code className={className} {...props}>
                                    {children}
                                    </code>
                                )
                            }
                        }}
                    >
                        {message.content}
                    </ReactMarkdown>
                </div>
                 {!isUser && message.content && (
                    <button onClick={handleCopy} className="absolute -top-2 -right-2 p-1.5 bg-gray-600 text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity">
                        {hasCopied ? <Check size={14} /> : <Copy size={14} />}
                    </button>
                 )}
            </div>

            {isUser && <div className="flex-shrink-0 p-2 bg-gray-700 rounded-full text-white"><User size={20} /></div>}
        </div>
    );
};

const WelcomeMessage: React.FC = () => (
    <div className="text-center p-8 text-gray-600 dark:text-gray-400">
        <Bot size={48} className="mx-auto mb-4 text-indigo-400" />
        <h2 className="text-2xl font-bold mb-2 text-gray-800 dark:text-white">Welcome to Nexus AI</h2>
        <p>Select a model from the top right and start a conversation.</p>
    </div>
);


export default ChatScreen;

import React, { useState, useCallback } from 'react';
import { generateCode } from '../services/aiService';
import { Bot, Wand2, Copy, Check } from 'lucide-react';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { vscDarkPlus } from 'react-syntax-highlighter/dist/esm/styles/prism';

const AppBuilderScreen: React.FC = () => {
    const [prompt, setPrompt] = useState('');
    const [generatedCode, setGeneratedCode] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const [hasCopied, setHasCopied] = useState(false);

    const handleGenerateCode = useCallback(async () => {
        if (!prompt.trim() || isLoading) return;
        setIsLoading(true);
        setGeneratedCode('');
        try {
            const code = await generateCode(prompt);
            const codeBlock = code.match(/```(?:tsx|typescript|jsx|javascript|html)\n([\s\S]*?)```/);
            setGeneratedCode(codeBlock ? codeBlock[1] : code);
        } catch (error) {
            console.error("Failed to generate code:", error);
            setGeneratedCode("// An error occurred while generating the code.\n// Please check the console for more details.");
        } finally {
            setIsLoading(false);
        }
    }, [prompt, isLoading]);

    const handleCopy = () => {
        if (!generatedCode) return;
        navigator.clipboard.writeText(generatedCode);
        setHasCopied(true);
        setTimeout(() => setHasCopied(false), 2000);
    };

    return (
        <div className="flex-1 flex flex-col h-full p-4 gap-4 bg-transparent">
            {/* Header */}
            <header className="flex-shrink-0 flex justify-between items-center p-4 rounded-xl bg-white/30 dark:bg-black/30 backdrop-blur-lg border border-white/20 dark:border-white/10 shadow-md">
                <div className="flex items-center gap-3">
                    <Wand2 className="text-indigo-500" size={28} />
                    <div>
                        <h2 className="text-xl font-bold text-gray-800 dark:text-white">AI App Builder</h2>
                        <p className="text-sm text-gray-600 dark:text-gray-400">Describe the component you want to build.</p>
                    </div>
                </div>
            </header>

            {/* Main Content */}
            <div className="flex-1 flex flex-col md:flex-row gap-4 overflow-hidden">
                {/* Prompt Input */}
                <div className="md:w-1/3 flex flex-col gap-4">
                    <div className="flex-1 flex flex-col p-4 rounded-xl bg-white/30 dark:bg-black/30 backdrop-blur-lg border border-white/20 dark:border-white/10 shadow-inner">
                        <textarea
                            value={prompt}
                            onChange={(e) => setPrompt(e.target.value)}
                            placeholder="e.g., 'A login form with email, password, and a remember me checkbox'"
                            className="w-full h-full flex-1 bg-white/50 dark:bg-black/50 text-gray-800 dark:text-gray-200 placeholder-gray-500 dark:placeholder-gray-400 p-4 rounded-lg border-2 border-transparent focus:border-indigo-500 focus:ring-0 transition-colors resize-none"
                        />
                    </div>
                    <button
                        onClick={handleGenerateCode}
                        disabled={isLoading}
                        className="w-full flex items-center justify-center gap-2 bg-indigo-500 text-white rounded-lg p-4 disabled:bg-indigo-300 hover:bg-indigo-600 transition-all duration-200 font-bold text-lg"
                    >
                        {isLoading ? (
                            <>
                                <div className="w-6 h-6 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                                Generating...
                            </>
                        ) : (
                             <>
                                <Wand2 size={20} /> Generate Code
                            </>
                        )}
                    </button>
                </div>

                {/* Code Display */}
                <div className="md:w-2/3 flex flex-col rounded-xl bg-black/50 backdrop-blur-lg border border-white/10 shadow-lg overflow-hidden relative">
                    {generatedCode ? (
                        <>
                            <button onClick={handleCopy} className="absolute top-4 right-4 p-2 bg-gray-700 text-white rounded-lg hover:bg-gray-600 transition-colors z-10">
                                {hasCopied ? <Check size={20} /> : <Copy size={20} />}
                            </button>
                            <SyntaxHighlighter
                                language="tsx"
                                style={vscDarkPlus}
                                customStyle={{
                                    height: '100%',
                                    width: '100%',
                                    margin: 0,
                                    padding: '1.5rem',
